protected void burstToken(String token, boolean stopAtNonOption)
{
    for (int i = 0; i < token.length(); i++)
    {
        String ch = String.valueOf(token.charAt(i));

        if (!ch.startsWith("-") || options.hasOption(ch))
        {
            if(!tokens.isEmpty() && tokens.get(tokens.size()-1).endsWith(ch)){
               int index  = tokens.size()-1;
               tokens.set(index ,tokens.get(index )+ch);
                continue;
           }

            if (stopAtNonOption  && (!ch.startsWith("-") || currentOption == null))
            {
                processRemaining(token.substring(i),stopAtNonOption);
                  return;
            }

              if (ch.equals(" ")) continue;

             if (currentOption != null)
            {

                if (currentOption.hasArgs())
                {
                    if(i+ 1== token.length()){
                        addArgument(ch,stopAtNonOption);

                    }else{
                       addArgument(token.substring(i),stopAtNonOption );
                    }  

                     i += currentOption.getValue().length()-1;
                    tokens.add("\n");
                    currentOption=null;

                      continue ;
                }
                else
                {
                    tokens.add("-" + ch);
                    currentOption = null;
                     continue ;
                }
            }


            if (stopAtNonOption && !ch.startsWith("-"))
            {
                processRemaining(token.substring(i),stopAtNonOption);
                  return;
            }
        }
        else if (stopAtNonOption)
        {
          //  process(token.substring(i));
            break;
        }
        else
        {
           // tokens.add(token);
            break;
        }
      //process(token.substring(i));

        if(i+ 1== token.length()){
            tokens.add(token.substring(i ));
        }
    }
}
private void addArgument(String arg,boolean stopAtNonOption){
     if (arg.length() == 0) return;
    if(stopAtNonOption && arg.contains(" ")&& !arg.endsWith(" ")){
       String lastWord = arg.substring(arg.lastIndexOf(" ") + 1);
       arg=arg.replaceFirst(Pattern.quote(lastWord),"");

        tokens.add(lastWord);

    }
    tokens.add(arg);
}
private void processRemaining(String remaining,boolean stopAtNonOption){
      if (remaining.length() > 0)
        {

            if(stopAtNonOption&& remaining.contains(" ")&& !remaining.endsWith(" ")){

                String lastWord = remaining.substring(remaining.lastIndexOf(" ") + 1);


                remaining=remaining.replaceFirst(Pattern.quote(lastWord),"");


                tokens.addAll(Arrays.asList(remaining.split("\\s+")));
                tokens.add(lastWord);


            }


            tokens.addAll(Arrays.asList(remaining.split("\\s+")));

        }

}

